import scala.concurrent.{Future, ExecutionContext}
import scala.util.{Success, Failure}

def fetchUser(id: String)(implicit ec: ExecutionContext): Future[User] = {
  api.get(s"/users/$id").map(_.data).recoverWith {
    case ex => Future.failed(new RuntimeException(s"Failed to fetch: ${ex.getMessage}"))
  }
}

